import React from 'react';
import ParamHeader from './ParamHeader';

function Volume({ volume, onVolumeChange, paramIcons, onIconClick, buttonRefs }) {
  return (
    <div className="bg-white/60 backdrop-blur-sm rounded-2xl p-4 shadow-lg">
      <div className="flex items-center justify-between mb-2">
        <ParamHeader
          paramKey="volume"
          label="音量"
          iconColor="text-purple-500"
          onIconClick={onIconClick}
          buttonRef={(el) => buttonRefs.current.volume = el}
        />
        <span className="text-sm font-bold text-purple-500">{volume}%</span>
      </div>
      <input
        type="range"
        min="0"
        max="100"
        value={volume}
        onChange={(e) => onVolumeChange(parseInt(e.target.value))}
        className="w-full h-2 bg-gradient-to-r from-purple-200 to-purple-400 rounded-full appearance-none cursor-pointer [&::-webkit-slider-thumb]:appearance-none [&::-webkit-slider-thumb]:w-5 [&::-webkit-slider-thumb]:h-5 [&::-webkit-slider-thumb]:rounded-full [&::-webkit-slider-thumb]:bg-white [&::-webkit-slider-thumb]:shadow-lg [&::-webkit-slider-thumb]:border-2 [&::-webkit-slider-thumb]:border-purple-400"
      />
    </div>
  );
}

export default Volume;
